    fn default() -> Self {
        Counter { value: 0 }
    }
}

fn main() {
    let counter = Arc::new(Mutex::new(Counter::default()));
    let mut handles = vec![];

    for i in 1..=5 {
        let counter_clone = Arc::clone(&counter);
        let handle = std::thread::spawn(move || {
            let mut data = counter_clone.lock().unwrap();
            data.value += i as i32;
            println!("Thread {} updated value to {}", i, data.value);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_data = counter.lock().unwrap();
    println!("Final total: {}", final_data.value);
