use std::thread;
use std::sync::Arc;

struct SharedData {
    value: i32,
}

unsafe impl Send for SharedData {}
unsafe impl Sync for SharedData {}

fn main() {
    let input_data = Arc::new(SharedData { value: 42 });
    let num_threads = 5;
    let mut handles = vec![];

    for i in 0..num_threads {
        let data_clone = Arc::clone(&input_data);
        let handle = thread::spawn(move || {
            println!("Thread {} starting with value: {}", i, data_clone.value);
            thread::sleep(std::time::Duration::from_millis(10));
            let result = data_clone.value * (i + 1);
            println!("Thread {} finished. Result: {}", i, result);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}

